public class C_Round_119_Div1 {

  public static long MOD = 1000000007;

  public static void main(String[] args) throws FileNotFoundException {

    PrintWriter out = new PrintWriter(System.out);
    Scanner in = new Scanner();
    int n = in.nextInt();
    int m = in.nextInt();
    int k = in.nextInt();
    boolean[] check = new boolean[n];
    for (int i = 0; i < k; i++) {
      check[in.nextInt() - 1] = true;
    }
    ArrayList<Integer>[] map = new ArrayList[n];
    for (int i = 0; i < n; i++) {
      map[i] = new ArrayList();
    }
    for (int i = 0; i < m; i++) {
      int a = in.nextInt() - 1;
      int b = in.nextInt() - 1;
      map[a].add(b);
      map[b].add(a);
    }
    int s = in.nextInt() - 1;
    int t = in.nextInt() - 1;
    int st = 0;
    int ed = n;
    int result = -1;
    int[] dist = new int[n];
    PriorityQueue<Point> q = new PriorityQueue<>();
    while (st <= ed) {
      int mid = (st + ed) >> 1;

      if (cal(mid, s, t, dist, check, map)) {
        if (result == -1 || result > mid) {
          result = mid;
        }
        ed = 0;
        for (int i : dist) {
          ed = Math.max(i, ed);
        }
        ed = Math.min(mid - 1, ed);

        if (cal(ed, s, t, dist, check, map)) {
          if (result == -1 || result > ed) {
            result = ed;
          }
          ed = ed - 1;
        } else {
          st = ed + 1;
          ed = mid - 1;
        }
      } else {
        st = mid + 1;
      }
    }
    out.println(result);

    out.close();
  }

  public static boolean cal(
      int mid, int s, int t, int[] dist, boolean[] check, ArrayList<Integer>[] map) {
    PriorityQueue<Point> q = new PriorityQueue<>();

    Arrays.fill(dist, -1);
    dist[s] = 0;
    q.add(new Point(0, s));
    while (!q.isEmpty()) {
      Point p = q.poll();
      if (dist[p.y] == p.x && p.x + 1 <= mid) {
        for (int i : map[p.y]) {
          if (dist[i] == -1 || dist[i] > 1 + p.x) {
            dist[i] = 1 + p.x;
            if (check[i]) {
              dist[i] = 0;
            }
            q.add(new Point(dist[i], i));
          }
        }
      }
    }
    return dist[t] != -1;
  }

  static class Dist implements Comparable<Dist> {

    int pos, max, nearest;

    public Dist(int pos, int max, int nearest) {
      this.pos = pos;
      this.max = max;
      this.nearest = nearest;
    }

    @Override
    public int compareTo(Dist o) {
      if (max != o.max) {
        return Integer.compare(max, o.max);
      }
      return Integer.compare(nearest, o.nearest);
    }

    @Override
    public String toString() {
      return "Dist{" + "pos=" + pos + ", max=" + max + ", nearest=" + nearest + '}';
    }
  }

