    public Point(int start, int end) {
      this.x = start;
      this.y = end;
    }

    @Override
    public int hashCode() {
      int hash = 5;
      hash = 47 * hash + this.x;
      hash = 47 * hash + this.y;
      return hash;
    }

    @Override
    public boolean equals(Object obj) {
      if (obj == null) {
        return false;
      }
      if (getClass() != obj.getClass()) {
        return false;
      }
      final Point other = (Point) obj;
      if (this.x != other.x) {
        return false;
      }
      if (this.y != other.y) {
        return false;
      }
      return true;
    }

    @Override
    public int compareTo(Point o) {
      return x - o.x;
    }
  }

  public static class FT {

    long[] data;

    FT(int n) {
      data = new long[n];
    }

    public void update(int index, long value) {
      while (index < data.length) {
        data[index] += value;
        index += (index & (-index));
      }
    }

    public long get(int index) {
      long result = 0;
      while (index > 0) {
        result += data[index];
        index -= (index & (-index));
      }
      return result;
    }
  }

  public static long gcd(long a, long b) {
    if (b == 0) {
