  public static void main(String[] args) {
    new Thread(new C()).start();
  }

  int n;
  boolean[] volunteer;

  class VList {
    List<Integer> list = new LinkedList<Integer>();
  }

  VList[] e;
  int src, dst;

  LinkedList<Integer> dQueue;
  int[] dBest;
  boolean[] inQueue;

  private void solve() throws IOException {
    n = nextInt();
    int m = nextInt();

    volunteer = new boolean[n];
    int vCnt = nextInt();
    for (int k = 0; k < vCnt; k++) {
      int u = nextInt() - 1;
      volunteer[u] = true;
    }

    e = new VList[n];
    for (int i = 0; i < n; i++) {
      e[i] = new VList();
    }

    for (int k = 0; k < m; k++) {
      int u = nextInt() - 1;
      int v = nextInt() - 1;
      e[u].list.add(v);
      e[v].list.add(u);
    }

    src = nextInt() - 1;
    dst = nextInt() - 1;

    for (int i = 0; i < n; i++) {
      Collections.reverse(e[i].list);
    }

    dQueue = new LinkedList<Integer>();
    dBest = new int[n];
    inQueue = new boolean[n];

    if (!reachable(n)) {

      out.print("-1");

    } else {

      int lo = 1;
      int hi = n;
      while (lo < hi) {
        int mid = (lo + hi) / 2;
        if (reachable(mid)) {
          hi = mid;
        } else {
          lo = mid + 1;
        }
      }

      out.print(lo);
    }
  }

  private boolean reachable(int maxD) {
    dQueue.clear();
    Arrays.fill(dBest, Integer.MAX_VALUE);
    Arrays.fill(inQueue, false);

    dBest[src] = 0;
    dQueue.add(src);
    inQueue[src] = true;

