    OutputStream outputStream = System.out;
    InputReader in = new InputReader(inputStream);
    OutputWriter out = new OutputWriter(outputStream);

    int N = in.readInt();
    int M = in.readInt();
    int K = in.readInt();

    int[] HH = IOUtils.readIntArray(in, K);
    boolean[] H = new boolean[N];
    for (int i = 0; i < K; i++) {
      int x = HH[i] - 1;
      H[x] = true;
    }

    ArrayList<Integer>[] adj = new ArrayList[N];
    for (int i = 0; i < N; i++) adj[i] = new ArrayList<Integer>();

    int[][] F = new int[2][M];
    IOUtils.readIntArrays(in, F[0], F[1]);

    for (int k = 0; k < M; k++) {
      int i = F[0][k] - 1;
      int j = F[1][k] - 1;

      adj[i].add(j);
      adj[j].add(i);
