    State[] q = new State[N + M + 10];
    for (int i = 0; i < q.length; i++) q[i] = new State(0, 0);

    int first = 0, last = 0;
    boolean[] v = new boolean[N];

    int lo = 1, hi = N + 10;
    while (lo < hi) {
      int Q = (lo + hi) / 2;

      for (int i = 0; i < N; i++) p[i] = i;

      first = last = 0;
      Arrays.fill(v, false);

      for (int i = 0; i < N; i++)
        if (H[i]) {
          q[last].i = i;
          q[last].d = 0;
          last = (last + 1) % q.length;
          v[i] = true;
        }

      while (last != first) {
        State st = q[first];
        first = (first + 1) % q.length;

        for (int j : adj[st.i]) {
          if (2 * (st.d + 1) <= Q) union(st.i, j, p);

          if (!v[j] && 2 * (st.d + 1) <= Q) {
            v[j] = true;
            q[last].i = j;
            q[last].d = st.d + 1;
            last = (last + 1) % q.length;
          }
