public class Main {
  public static void main(String[] args) throws IOException {

    InputStream inputStream = System.in;
    OutputStream outputStream = System.out;
    InputReader in = new InputReader(inputStream);
    OutputWriter out = new OutputWriter(outputStream);

    int N = in.readInt();
    int M = in.readInt();
    int K = in.readInt();

    int[] HH = IOUtils.readIntArray(in, K);
    boolean[] H = new boolean[N];
    for (int i = 0; i < K; i++) {
      int x = HH[i] - 1;
      H[x] = true;
    }

    ArrayList<Integer>[] adj = new ArrayList[N];
    for (int i = 0; i < N; i++) adj[i] = new ArrayList<Integer>();

    int[][] F = new int[2][M];
    IOUtils.readIntArrays(in, F[0], F[1]);

    for (int k = 0; k < M; k++) {
      int i = F[0][k] - 1;
      int j = F[1][k] - 1;

      adj[i].add(j);
      adj[j].add(i);
    }

    int s = in.readInt() - 1;
    int e = in.readInt() - 1;

    H[e] = true;

    int[] p = new int[N];
    State[] q = new State[N + M + 10];
    for (int i = 0; i < q.length; i++) q[i] = new State(0, 0);

    int first = 0, last = 0;
    boolean[] v = new boolean[N];

    int lo = 1, hi = N + 10;
    while (lo < hi) {
      int Q = (lo + hi) / 2;

      for (int i = 0; i < N; i++) p[i] = i;

      first = last = 0;
      Arrays.fill(v, false);

      for (int i = 0; i < N; i++)
        if (H[i]) {
          q[last].i = i;
          q[last].d = 0;
          last = (last + 1) % q.length;
          v[i] = true;
        }

      while (last != first) {
        State st = q[first];
        first = (first + 1) % q.length;

        for (int j : adj[st.i]) {
          if (2 * (st.d + 1) <= Q) union(st.i, j, p);

          if (!v[j] && 2 * (st.d + 1) <= Q) {
            v[j] = true;
            q[last].i = j;
            q[last].d = st.d + 1;
            last = (last + 1) % q.length;
          }
        }
      }

      if (Q % 2 != 0)
        for (int i = 0; i < N; i++)
          for (int j : adj[i]) {
            if (v[i] && v[j]) union(i, j, p);
          }

      if (find(s, p) == find(e, p)) hi = Q;
      else lo = Q + 1;
    }

    if (lo > N) System.out.println(-1);
    else System.out.println(lo);
  }

  static int find(int i, int[] p) {
    if (p[i] == i) return i;
    else return p[i] = find(p[i], p);
  }

  static void union(int i, int j, int[] p) {
    p[find(j, p)] = find(i, p);
  }
}

class State {
  int i, d;

  public State(int ii, int di) {
    i = ii;
    d = di;
  }
}

class DisjointSets {
  static int[] p, rank;

  public DisjointSets(int n) {
    p = new int[n];
    rank = new int[n];
    for (int i = 0; i < n; i++) p[i] = i;
  }

  static void create(int x) {
    p[x] = x;
    rank[x] = 0;
  }

  static void union(int x, int y) {
    int px = find(x);
    int py = find(y);
    if (rank[px] > rank[py]) p[py] = px;
    else p[px] = py;
    if (rank[px] == rank[py]) rank[py] = rank[py] + 1;
  }

  static int find(int x) {
    if (x != p[x]) p[x] = find(p[x]);
    return p[x];
  }
}

class InputReader {

  private InputStream stream;
  private byte[] buf = new byte[1024];
  private int curChar;
  private int numChars;

  public InputReader(InputStream stream) {
    this.stream = stream;
  }

  public int read() {
    if (numChars == -1) throw new InputMismatchException();
    if (curChar >= numChars) {
      curChar = 0;
      try {
        numChars = stream.read(buf);
      } catch (IOException e) {
        throw new InputMismatchException();
      }
      if (numChars <= 0) return -1;
    }
    return buf[curChar++];
  }

  public int readInt() {
    int c = read();
    while (isSpaceChar(c)) c = read();
    int sgn = 1;
    if (c == '-') {
      sgn = -1;
      c = read();
    }
    int res = 0;
    do {
      if (c < '0' || c > '9') throw new InputMismatchException();
      res *= 10;
      res += c - '0';
      c = read();
    } while (!isSpaceChar(c));
    return res * sgn;
  }

  public static boolean isSpaceChar(int c) {
    return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
  }
}

