public class vest {

  public static int fit(int a, int b, int x, int y) {

    if (a - x > b) return 1;
    if (a + y < b) return 2;
    return 0;
  }

  public static void main(String[] args) {

    Scanner sc = new Scanner(System.in);

    int n = sc.nextInt();
    int m = sc.nextInt();
    int x = sc.nextInt();
