import java.util.Arrays;
import java.util.Comparator;
import java.util.Scanner;

public class Dressem_in_Vests {

  public static void solve() {
    Scanner nera = new Scanner(System.in);

    int n = nera.nextInt();
    int m = nera.nextInt();
    int x = nera.nextInt();
    int y = nera.nextInt();
    int i = 0, j = 0, k = 0;
    int a[][] = new int[n][2];
    int b[][] = new int[m][2];

    for (i = 0; i < n; ++i) {
      a[i][0] = i;
      a[i][1] = nera.nextInt();
    }
    for (i = 0; i < m; ++i) {
      b[i][0] = i;
      b[i][1] = nera.nextInt();
    }

    Arrays.sort(
        a,
        new Comparator<int[]>() {

          @Override
          public int compare(int[] o1, int[] o2) {
            int a1 = o1[1];
            int b1 = o2[1];

            return (a1 >= b1 ? 1 : -1);
          }
        });
    Arrays.sort(
        b,
        new Comparator<int[]>() {

          @Override
          public int compare(int[] o1, int[] o2) {
            int a1 = o1[1];
            int b1 = o2[1];

            return (a1 >= b1 ? 1 : -1);
          }
        });
    int z[][] = new int[Math.max(n, m)][2];
    int sum = 0, count = 0;
    int q = 0;
    int temp = b[j][1];
    for (j = 0; j < m; ++j) {
      if (q != n)
        for (i = q; i < n; ++i) {
          q++;
          if (temp >= (a[i][1] - x) && temp <= (a[i][1] + y)) {
            sum++;
            z[k][0] = i + 1;
            z[k][1] = j + 1;
            k++;
            count++;
            if (j + 1 != m) temp = b[j + 1][1];
            break;
          } else if (temp < (a[i][1] - x)) {
            if (j + 1 != m) temp = b[j + 1][1];
            q--;
            break;
          }
        }
    }

    System.out.println(sum);
    i = 0;
    while (i < count) {
      System.out.println(z[i][0] + " " + z[i][1]);
      ++i;
    }
  }

  public static void main(String[] args) {

    solve();
  }
}

