    for (int i = 0; i < m; i++) b[i] = sc.nextInt();

    int u = 0;
    int v = 0;
    int temp;
    ArrayList<Integer> result = new ArrayList<Integer>();

    while (u < n && v < m) {
      temp = fit(a[u], b[v], x, y);
      if (temp == 1) v++;
      if (temp == 2) u++;
      if (temp == 0) {
        result.add(u + 1);
        result.add(v + 1);
        u++;
        v++;
      }
    }

    System.out.println(result.size() / 2);

