public class e {

  public static int n;
  public static ArrayList<item> list;

  public static void main(String[] args) throws Exception {

    BufferedReader stdin = new BufferedReader(new InputStreamReader(System.in));
    n = Integer.parseInt(stdin.readLine());
    StringTokenizer tok = new StringTokenizer(stdin.readLine());
    list = new ArrayList<item>();
    for (int i = 0; i < n; i++) {
      int x = Integer.parseInt(tok.nextToken());
      list.add(new item(x, i));
    }
    Collections.sort(list);

    System.out.println(solve());
  }

  public static long solve() {

    int i = 0;

    while (i < n - 1 && list.get(i).value == list.get(i + 1).value) i++;
    i++;

    if (i == n) return n;

    while (i < n) {

      int j = i;
      while (j < n - 1 && list.get(j).value == list.get(j + 1).value) j++;

      if (j > i) {

        int lastpos = list.get(i - 1).index;

        int k = -1;
        for (k = i; k <= j; k++) {
          if (list.get(k).index > lastpos) {
            break;
          }
        }

        if (k > i) {

          item[] tmp = new item[j - i + 1];
          for (int z = i; z <= j; z++) {
            int ind = k + z - i;
            if (ind > j) ind -= (j - i + 1);
            tmp[z - i] = list.get(ind);
          }
          for (int z = i; z <= j; z++) list.set(z, tmp[z - i]);
        }
      }

      i = j + 1;
    }

    int[] arr = new int[n];
    for (i = 0; i < n; i++) {
      arr[i] = list.get(i).index + 1;
    }

    long res = 0;
    bit mybit = new bit(n);

    for (i = 0; i < n; i++) {

      if (i == 0) {
        res += arr[i];
      } else {

        if (arr[i] > arr[i - 1]) {
          int range = arr[i] - arr[i - 1];

          res += (range - mybit.sum(arr[i - 1] + 1, arr[i]));
        } else {
          int range = arr[i - 1] - arr[i] - 1;
          range = n - range;
          long used = mybit.atOrAbove(arr[i - 1]) + mybit.sum(1, arr[i]);

          res += (range - used);
        }
      }

      mybit.add(arr[i], 1L);
    }

    return res;
  }
}

class item implements Comparable<item> {

  public int value;
  public int index;

  public item(int v, int i) {
    value = v;
    index = i;
  }

  public int compareTo(item other) {
    if (this.value != other.value) return this.value - other.value;
    return this.index - other.index;
  }
}

class bit {

  public long[] cumfreq;

  public bit(int n) {

    int size = 1;
    while (size < n) size <<= 1;
    n = size;

    cumfreq = new long[n + 1];
  }

  public void add(int index, long value) {
    while (index < cumfreq.length) {
      cumfreq[index] += value;
      index += Integer.lowestOneBit(index);
    }
  }

  public long sum(int index) {
    long ans = 0;
    while (index > 0) {
      ans += cumfreq[index];
      index -= (Integer.lowestOneBit(index));
    }
    return ans;
  }

  public long sum(int low, int high) {
    return sum(high) - sum(low - 1);
  }

  public long all() {
    return sum(cumfreq.length - 1);
  }

  public long atOrAbove(int index) {
    long sub = 0;
    if (index > 0) sub = sum(index - 1);
    return all() - sub;
  }
}

