  static class SegmentTree {
    int n;
    int[] t;

    SegmentTree(int nn) {
      n = nn;
      t = new int[n << 1 << 1];
      build(1, 0, n - 1);
    }

    void build(int node, int s, int e) {
      if (s == e) t[node] = 1;
      else {
        int mid = (s + e) >> 1;
        build(node << 1, s, mid);
        build(node << 1 | 1, mid + 1, e);
        t[node] = t[node << 1] + t[node << 1 | 1];
      }
    }

    void update(int idx) {
      update(1, 0, n - 1, idx);
    }

    void update(int node, int s, int e, int idx) {
      if (s == e && s == idx) t[node] = 0;
      else if (idx > e || idx < s) return;
      else {
        int mid = (s + e) >> 1;
        update(node << 1, s, mid, idx);
        update(node << 1 | 1, mid + 1, e, idx);
        t[node] = t[node << 1] + t[node << 1 | 1];
      }
    }

    int query(int s, int e) {
      return query(1, 0, n - 1, s, e);
    }

    int query(int node, int s, int e, int l, int r) {
      if (s >= l && e <= r) return t[node];
      else if (s > r || e < l) return 0;
      else {
        int mid = (s + e) >> 1;
        return query(node << 1, s, mid, l, r) + query(node << 1 | 1, mid + 1, e, l, r);
      }
    }
  }

