    int s = 0;
    int f = a.length;
    while (f > s) {
      int mid = (s + f) / 2;
      if (a[mid] > key) {
        f = mid - 1;
      } else if (a[mid] <= key) {
        s = mid + 1;
      }
    }
    return -1;
  }

