    int last = 0;
    Node min = seg.query(1, n);
    for (int i = 1; i <= n; i++) {
      Node node1 = seg.query(1, last - 1), node2 = seg.query(last + 1, n);
      if (node2.n <= node1.n) min = node2;
      else min = node1;

      if (min.idx > last) {
        int h = 0, l = 0;
        l = bit.low(last + 1);
        h = bit.low(min.idx + 1);

        sum += (long) (h - l);
      } else {
        int h = 0, l = 0;
        h = bit.high(last);
        l = bit.low(min.idx + 1);

        sum += (long) (h + l);
      }
