  static class BIT {
    public int bit[], n;

    public BIT(int nn) {
      n = nn;
      bit = new int[n + 1];
    }

    int low(int x) {
      return sum(x - 1);
    }

    int high(int x) {
      return sum(n) - sum(x);
    }

    void add(int x) {
      add(x, 1);
    }

    void remove(int x) {
      add(x, -1);
    }

    void add(int index, int value) {
      for (; index < bit.length; index = index + (index & -index)) {
        bit[index] += value;
      }
    }

    int sum(int index) {
      int sum = 0;
      for (; index > 0; index = index - (index & -index)) {
        sum += bit[index];
      }
      return sum;
    }
  }

  static class Node implements Comparable<Node> {
    int n, idx;

    Node(int N, int i) {
      n = N;
      idx = i;
    }

    public int compareTo(Node N) {
      if (n != N.n) return n - N.n;
      else return idx - N.idx;
    }

    public String toString() {
      return n + " " + idx;
    }
  }

  static class segTree {
    public int n;
    Node seg[];

    public segTree(int N) {
      n = N;
      seg = new Node[4 * (int) 1e5];
      for (int i = 0; i < seg.length; i++) {
        seg[i] = new Node(0, 0);
      }
    }

    public void update(int pos, int val) {
      update(1, 1, n, pos, val);
    }

    public Node query(int l, int r) {
      if (l < 1 || r < 1 || l > r || l > n || r > n) return new Node((int) 2e9, 1000000);
      return query(1, 1, n, l, r);
    }

    public void update(int p, int s, int e, int pos, int val) {
      if (s == pos && e == pos) {
        seg[p].n = val;
        seg[p].idx = pos;
        return;
      }
      if (s > pos || e < pos || s > e || e < s) return;

      int m = (s + e) / 2, l = 2 * p, r = 2 * p + 1;

      update(l, s, m, pos, val);
      update(r, m + 1, e, pos, val);

      if (seg[l].n <= seg[r].n) {
