    public void solve(int testNumber, FastScanner in, PrintWriter out) {
      int n = in.nextInt();
      int[] a = new int[n];
      for (int i = 0; i < n; i++) {
        a[i] = in.nextInt();
      }
      int k = repaint(a);
      int[] nextSame = new int[n];
      int[] nextLarger = new int[n];
      int[] last = new int[k + 1];
      Arrays.fill(last, -1);
      for (int step = 0; step < 2 * n; step++) {
        int i = -step % n;
        if (i < 0) {
          i += n;
        }
        nextSame[i] = last[a[i]];
        nextLarger[i] = last[a[i] + 1];
        last[a[i]] = i;
      }

      int[] tree = new int[n];
      for (int i = 0; i < n; i++) {
        add(tree, i, 1);
      }
      int first = -1;
      for (int i = 0; i < n; i++) {
        if (a[i] == 0) {
          first = i;
          break;
        }
      }
      long ans = 0;
      int x = 0;
      for (int i = 0; i < n; i++) {
        int nx;
        if (i == 0) {
          nx = first;
        } else if (sum(tree, nextSame[x], nextSame[x]) > 0) {
          nx = nextSame[x];
        } else {
          nx = nextLarger[x];
        }
        if (x <= nx) {
          ans += sum(tree, x, nx);
        } else {
          ans += sum(tree, x, n - 1);
          ans += sum(tree, 0, nx);
        }
        x = nx;
        add(tree, x, -1);
      }
      out.println(ans);
    }

    private void add(int[] tree, int pos, int val) {
      while (pos < tree.length) {
        tree[pos] += val;
        pos |= pos + 1;
      }
    }

    private int sum(int[] tree, int l, int r) {
      return sum(tree, r) - sum(tree, l - 1);
    }

    private int sum(int[] tree, int r) {
      int res = 0;
      while (r >= 0) {
        res += tree[r];
        r = (r & (r + 1)) - 1;
      }
      return res;
    }

    private int repaint(int[] a) {
      int[] b = a.clone();
      randomShuffle(b);
      Arrays.sort(b);
      int k = 0;
      for (int i = 0; i < b.length; i++) {
