    int arr[] = new int[n + 1];
    segTree seg = new segTree(n);
    BIT bit = new BIT((int) 1e5 + 50);
    for (int i = 1; i <= n; i++) {
      arr[i] = in.nextInt();
      seg.update(i, arr[i]);
      bit.add(i);
    }

    long sum = 0;
    int last = 0;
    Node min = seg.query(1, n);
    for (int i = 1; i <= n; i++) {
      Node node1 = seg.query(1, last - 1), node2 = seg.query(last + 1, n);
      if (node2.n <= node1.n) min = node2;
      else min = node1;

      if (min.idx > last) {
        int h = 0, l = 0;
        l = bit.low(last + 1);
        h = bit.low(min.idx + 1);

        sum += (long) (h - l);
      } else {
        int h = 0, l = 0;
        h = bit.high(last);
        l = bit.low(min.idx + 1);

        sum += (long) (h + l);
      }
      bit.remove(min.idx);
      last = min.idx;
      seg.update(min.idx, (int) 2e9);
    }

    pw.println(sum);

    pw.close();
  }

  static class BIT {
    public int bit[], n;

    public BIT(int nn) {
      n = nn;
      bit = new int[n + 1];
    }

    int low(int x) {
      return sum(x - 1);
    }

    int high(int x) {
      return sum(n) - sum(x);
    }

    void add(int x) {
      add(x, 1);
    }

    void remove(int x) {
      add(x, -1);
    }

    void add(int index, int value) {
      for (; index < bit.length; index = index + (index & -index)) {
        bit[index] += value;
      }
    }

    int sum(int index) {
      int sum = 0;
      for (; index > 0; index = index - (index & -index)) {
        sum += bit[index];
      }
      return sum;
    }
  }

  static class Node implements Comparable<Node> {
    int n, idx;

    Node(int N, int i) {
      n = N;
      idx = i;
    }

    public int compareTo(Node N) {
      if (n != N.n) return n - N.n;
      else return idx - N.idx;
    }

