      ans += cumfreq[index];
      index -= (Integer.lowestOneBit(index));
    }
    return ans;
  }

  public long sum(int low, int high) {
    return sum(high) - sum(low - 1);
  }

  public long all() {
    return sum(cumfreq.length - 1);
  }

  public long atOrAbove(int index) {
    long sub = 0;
    if (index > 0) sub = sum(index - 1);
    return all() - sub;
