  static class SegmentTree {
    int n;
    int[] t;

    SegmentTree(int nn) {
      n = nn;
      t = new int[n << 1 << 1];
      build(1, 0, n - 1);
    }

    void build(int node, int s, int e) {
      if (s == e) t[node] = 1;
      else {
        int mid = (s + e) >> 1;
        build(node << 1, s, mid);
        build(node << 1 | 1, mid + 1, e);
        t[node] = t[node << 1] + t[node << 1 | 1];
