    }

    void update(int node, int s, int e, int idx) {
      if (s == e && s == idx) t[node] = 0;
      else if (idx > e || idx < s) return;
      else {
        int mid = (s + e) >> 1;
        update(node << 1, s, mid, idx);
        update(node << 1 | 1, mid + 1, e, idx);
        t[node] = t[node << 1] + t[node << 1 | 1];
      }
    }

    int query(int s, int e) {
