    S = new PriorityQueue[N];
    G = new ArrayList[N];
    for (int i = 0; i < N; i++) {
      int a = in.nextInt();
      idmap.put(a, i);
      G[i] = new ArrayList<Edge>();
      S[i] = new PriorityQueue<Integer>();
      S[i].add(a);
    }
    for (int i = 0; i < N - 1; i++) {
      int a = in.nextInt() - 1;
      int b = in.nextInt() - 1;
      int c = in.nextInt();
      G[a].add(new Edge(b, c));
      G[b].add(new Edge(a, c));
    }

    ans = new int[N];
    long t2 = System.currentTimeMillis();
    int left = N;
    for (time = 0; ; time++) {
      while (S[0].size() > 0) {
        int p = S[0].poll();
        ans[idmap.get(p)] = time;
        left--;
      }
      if (left == 0) break;
      Arrays.fill(V, false);
      recur(0, -1, 0);
    }
