      Edge e = G[at].get(i);
      if (V[e.to]) {
        G[at].remove(i);
        i--;
        continue;
      }
      recur(e.to, at, e.cap);
    }
  }

  static int[] ans;
  static PriorityQueue<Integer>[] S, NS;
  static boolean[] V;
  static int N, time;
  static HashMap<Integer, Integer> idmap;
  static ArrayList<Edge>[] G;

  private static class Edge {
    int to, cap;

